# LSP tools exposed to the agent LLM
from typing import Any

# These are called by the agent via its tool-use loop

LSP_TOOLS: list[dict[str, Any]] = [
    {
        "name": "goto_definition",
        "description": (
            "Find where a symbol is defined. Provide the file path and the "
            "zero-indexed line/character position of the symbol. Returns a list "
            "of definition locations with file paths and line numbers."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "file_path": {"type": "string"},
                "line": {"type": "integer", "description": "Zero-indexed line"},
                "character": {"type": "integer", "description": "Zero-indexed character offset"},
            },
            "required": ["file_path", "line", "character"],
        },
    },
    {
        "name": "find_references",
        "description": (
            "Find all references to the symbol at the given position. Returns a list "
            "of locations where the symbol is used across the workspace."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "file_path": {"type": "string"},
                "line": {"type": "integer"},
                "character": {"type": "integer"},
            },
            "required": ["file_path", "line", "character"],
        },
    },
    {
        "name": "get_diagnostics",
        "description": (
            "Get the current type errors and warnings for a file from the language server. "
            "Returns a list of diagnostics with message, severity, and position."
        ),
        "input_schema": {
            "type": "object",
            "properties": {"file_path": {"type": "string"}},
            "required": ["file_path"],
        },
    },
]


async def handle_lsp_tool(
    lsp: LspClient, tool_name: str, tool_input: dict
) -> str:
    path = tool_input["file_path"]
    await lsp.did_open(path)  # idempotent if already open

    if tool_name == "goto_definition":
        locs = await lsp.get_definition(path, tool_input["line"], tool_input["character"])
        if not locs:
            return "No definition found."
        return "\n".join(
            f"{loc['uri']}:{loc['range']['start']['line']}:{loc['range']['start']['character']}"
            for loc in locs
        )

    if tool_name == "find_references":
        locs = await lsp.get_references(path, tool_input["line"], tool_input["character"])
        return f"{len(locs)} references found:\n" + "\n".join(
            f"{loc['uri']}:{loc['range']['start']['line']}"
            for loc in locs
        )

    if tool_name == "get_diagnostics":
        file_uri = f"file://{path}"
        await asyncio.sleep(0.3)  # allow server to push diagnostics
        diags = lsp.diagnostics.get(file_uri, [])
        if not diags:
            return "No diagnostics — file is clean."
        lines = []
        for d in diags:
            sev = {1: "error", 2: "warning", 3: "info", 4: "hint"}.get(d.get("severity", 1), "?")
            pos = d.get("range", {}).get("start", {})
            lines.append(f"[{sev}] line {pos.get('line')}: {d.get('message', '')}")
        return "\n".join(lines)

    return f"Unknown LSP tool: {tool_name}"
